<?php
namespace App\Services;
use App\Enums\DeviceCommandStatus; use App\Models\DeviceCommand; use App\Models\PrintOrder; use Illuminate\Support\Facades\Http; use RuntimeException;
class Esp32DeviceService { public function command(string $target,string $action,?PrintOrder $order=null):array{$path=$target==='locker'?"/api/locker/{$action}":"/api/servo/{$target}/{$action}";$record=DeviceCommand::create(['print_order_id'=>$order?->id,'command_type'=>$action,'target_servo'=>$target,'requested_payload'=>['path'=>$path],'status'=>DeviceCommandStatus::Pending,'attempted_at'=>now()]);try{if(config('queueless.hardware_simulation'))$payload=['success'=>true,'simulated'=>true,'target'=>$target,'state'=>$action];else{$response=Http::baseUrl(config('queueless.esp32.base_url'))->withHeader('X-API-Key',config('queueless.esp32.api_key'))->timeout(config('queueless.esp32.timeout'))->post($path);$response->throw();$payload=$response->json();if(!($payload['success']??false))throw new RuntimeException('ESP32 rejected the command.');}$record->update(['status'=>DeviceCommandStatus::Succeeded,'response_payload'=>$payload,'completed_at'=>now()]);return $payload;}catch(\Throwable $e){$record->update(['status'=>DeviceCommandStatus::Failed,'failure_message'=>$e->getMessage(),'completed_at'=>now()]);throw new RuntimeException('The locker controller did not complete the command.',0,$e);}} public function openCatcher(?PrintOrder $o=null):array{return $this->command('catcher','open',$o);} public function closeCatcher(?PrintOrder $o=null):array{return $this->command('catcher','close',$o);} public function openPickupDoor(?PrintOrder $o=null):array{return $this->command('pickup','open',$o);} public function closePickupDoor(?PrintOrder $o=null):array{return $this->command('pickup','close',$o);} public function openTrashDoor(?PrintOrder $o=null):array{return $this->command('trash','open',$o);} public function closeTrashDoor(?PrintOrder $o=null):array{return $this->command('trash','close',$o);} public function setLockerOccupied(?PrintOrder $o=null):array{return $this->command('locker','occupied',$o);} public function setLockerAvailable(?PrintOrder $o=null):array{return $this->command('locker','available',$o);} }
